SELECT (YEAR(?time) AS ?year) WHERE { 
  wd:Q3454781 wdt:P585 ?time .
} UNION {
  wd:Q3454781 skos:altLabel ?label .
  FILTER(LANG(?label) = "fr")
  BIND(REPLACE(STR(?label), ".*?(\\d{4}).*", "$1") AS ?year)
  FILTER(REGEX(STR(?label), "\\d{4}"))
}
LIMIT 1

